svg.script:
(function createStars() {
  const svgNS = "http://www.w3.org/2000/svg";
  const group = document.getElementById('starfield-bg');
  const colors = ['#ffffff', '#a0f0ff', '#40e0ff', '#7b68ee'];

  for(let i = 0; i < 220; i++) {
    const star = document.createElementNS(svgNS, 'circle');
    const cx = Math.random() * 1920;
    const cy = Math.random() * 600;
    const r = Math.random() * 1.4 + 0.3;
    const color = colors[Math.floor(Math.random() * colors.length)];
    const delay = Math.random() * 4;
    const duration = 2 + Math.random() * 3;

    star.setAttribute('cx', cx);
    star.setAttribute('cy', cy);
    star.setAttribute('r', r);
    star.setAttribute('fill', color);
    star.setAttribute('opacity', 0.3 + Math.random() * 0.5);

    const animate = document.createElementNS(svgNS, 'animate');
    animate.setAttribute('attributeName', 'opacity');
    animate.setAttribute('values', '0.2;0.8;0.2');
    animate.setAttribute('dur', duration + 's');
    animate.setAttribute('begin', delay + 's');
    animate.setAttribute('repeatCount', 'indefinite');

    star.appendChild(animate);
    group.appendChild(star);
  }
})();

(function createCometTrail() {
  const svgNS = "http://www.w3.org/2000/svg";
  const group = document.getElementById('comet-system');
  const path = document.getElementById('comet-path');
  const pathLength = path.getTotalLength();
  const particleCount = 50;

  for(let i = 0; i < particleCount; i++) {
    const particle = document.createElementNS(svgNS, 'circle');
    const size = 8 - (i * 0.14);
    const opacity = Math.max(0.1, 1 - (i * 0.018));
    const delay = i * 0.08;
    const hue = 190 + (i * 0.4); // Cyan to purple shift

    particle.setAttribute('r', Math.max(1.5, size));
    particle.setAttribute('fill', `hsl(${hue}, 100%, ${60 - i*0.3}%)`);
    particle.setAttribute('opacity', 0);

    const animateOpacity = document.createElementNS(svgNS, 'animate');
    animateOpacity.setAttribute('attributeName', 'opacity');
    animateOpacity.setAttribute('values', `0;${opacity};0`);
    animateOpacity.setAttribute('dur', '2.2s');
    animateOpacity.setAttribute('begin', delay + 's');
    animateOpacity.setAttribute('repeatCount', 'indefinite');

    const animateMotion = document.createElementNS(svgNS, 'animateMotion');
    animateMotion.setAttribute('dur', '12s');
    animateMotion.setAttribute('begin', delay + 's');
    animateMotion.setAttribute('repeatCount', 'indefinite');
    animateMotion.setAttribute('path', path.getAttribute('d'));

    particle.appendChild(animateOpacity);
    particle.appendChild(animateMotion);
    group.appendChild(particle);
  }

  // Lead comet head
  const head = document.createElementNS(svgNS, 'circle');
  head.setAttribute('r', 10);
  head.setAttribute('fill', '#ffffff');
  head.setAttribute('filter', 'url(#glow-intense)');

  const headMotion = document.createElementNS(svgNS, 'animateMotion');
  headMotion.setAttribute('dur', '12s');
  headMotion.setAttribute('repeatCount', 'indefinite');
  headMotion.setAttribute('path', path.getAttribute('d'));

  const headPulse = document.createElementNS(svgNS, 'animate');
  headPulse.setAttribute('attributeName', 'r');
  headPulse.setAttribute('values', '10;13;10');
  headPulse.setAttribute('dur', '1.5s');
  headPulse.setAttribute('repeatCount', 'indefinite');

  head.appendChild(headPulse);
  head.appendChild(headMotion);
  group.appendChild(head);
})();

(function createAmbientParticles() {
  const svgNS = "http://www.w3.org/2000/svg";
  const group = document.getElementById('ambient-particles');
  const count = 40;

  for(let i = 0; i < count; i++) {
    const p = document.createElementNS(svgNS, 'circle');
    const x = Math.random() * 1920;
    const y = Math.random() * 600;
    const r = Math.random() * 1.2 + 0.4;
    const duration = 15 + Math.random() * 25;
    const delay = Math.random() * 10;

    p.setAttribute('cx', x);
    p.setAttribute('cy', y);
    p.setAttribute('r', r);
    p.setAttribute('fill', Math.random() > 0.5 ? '#40e0ff' : '#ffffff');
    p.setAttribute('opacity', 0.2 + Math.random() * 0.4);

    const animate = document.createElementNS(svgNS, 'animate');
    animate.setAttribute('attributeName', 'cy');
    animate.setAttribute('values', `${y-30};${y+30};${y-30}`);
    animate.setAttribute('dur', duration + 's');
    animate.setAttribute('begin', delay + 's');
    animate.setAttribute('repeatCount', 'indefinite');

    const animate2 = document.createElementNS(svgNS, 'animate');
    animate2.setAttribute('attributeName', 'opacity');
    animate2.setAttribute('values', '0.1;0.5;0.1');
    animate2.setAttribute('dur', (duration/2) + 's');
    animate2.setAttribute('begin', delay + 's');
    animate2.setAttribute('repeatCount', 'indefinite');

    p.appendChild(animate);
    p.appendChild(animate2);
    group.appendChild(p);
  }
})();

(function initInteractions() {
  const svgNS = "http://www.w3.org/2000/svg";
  const svg = document.documentElement;
  const starGroup = document.getElementById('interactive-stars');
  const path = document.getElementById('comet-path');
  const pathLength = path.getTotalLength();

  // Config
  const STAR_COUNT = 300;
  const REPEL_RADIUS = 50;
  const REPEL_FORCE = 5;
  const MOUSE_REPEL = 3;
  const RETURN_DAMPING = 0.96;

  // Create interactive stars
  const stars = [];
  for(let i = 0; i < STAR_COUNT; i++) {
    const star = document.createElementNS(svgNS, 'circle');
    const x = 50 + Math.random() * 1820;
    const y = 40 + Math.random() * 520;
    const r = 0.6 + Math.random() * 1.8;
    const hue = Math.random() > 0.6 ? 190 : (Math.random() > 0.3 ? 200 : 0);
    const sat = hue === 0 ? 0 : 80 + Math.random() * 20;
    const light = 70 + Math.random() * 25;

    star.setAttribute('cx', x);
    star.setAttribute('cy', y);
    star.setAttribute('r', r);
    star.setAttribute('fill', `hsl(${hue}, ${sat}%, ${light}%)`);
    star.setAttribute('opacity', 0.5 + Math.random() * 0.5);
    star.setAttribute('filter', 'url(#glow)');

    starGroup.appendChild(star);
    stars.push({
      el: star,
      ox: x, oy: y, // original position
      dx: 0, dy: 0, // displacement
      r: r
    });
  }

  let mouseX = -9999, mouseY = -9999;

  svg.addEventListener('mousemove', (e) => {
    const rect = svg.getBoundingClientRect();
    mouseX = (e.clientX - rect.left) * (1920 / rect.width);
    mouseY = (e.clientY - rect.top) * (600 / rect.height);
  });

  svg.addEventListener('mouseleave', () => {
    mouseX = -9999; mouseY = -9999;
  });

  // Animation loop
  let time = 0;
  function animate() {
    time += 0.016;
    const cometPos = path.getPointAtLength((time % 12) / 12 * pathLength);

    stars.forEach(star => {
      // Comet repel
      const dx1 = star.el.cx.baseVal.value - cometPos.x;
      const dy1 = star.el.cy.baseVal.value - cometPos.y;
      const dist1 = Math.sqrt(dx1*dx1 + dy1*dy1);

      if(dist1 < REPEL_RADIUS) {
        const angle = Math.atan2(dy1, dx1);
        const force = (REPEL_RADIUS - dist1) / REPEL_RADIUS * REPEL_FORCE;
        star.dx += Math.cos(angle) * force;
        star.dy += Math.sin(angle) * force;
      }

      // Mouse repel
      if(mouseX > 0) {
        const dx2 = star.el.cx.baseVal.value - mouseX;
        const dy2 = star.el.cy.baseVal.value - mouseY;
        const dist2 = Math.sqrt(dx2*dx2 + dy2*dy2);

        if(dist2 < REPEL_RADIUS * 1.3) {
          const angle = Math.atan2(dy2, dx2);
          const force = (REPEL_RADIUS*1.3 - dist2) / (REPEL_RADIUS*1.3) * MOUSE_REPEL;
          star.dx += Math.cos(angle) * force;
          star.dy += Math.sin(angle) * force;
        }
      }

      // Return to origin + apply
      star.dx *= RETURN_DAMPING;
      star.dy *= RETURN_DAMPING;

      const newX = star.ox + star.dx;
      const newY = star.oy + star.dy;

      star.el.setAttribute('cx', newX);
      star.el.setAttribute('cy', newY);

      // Subtle size pulse based on displacement
      const pulse = 1 + Math.abs(star.dx + star.dy) * 0.02;
      star.el.setAttribute('r', star.r * pulse);
    });

    requestAnimationFrame(animate);
  }

  animate();
})();
